const fieldsData = $json?.data?.items || [];
const config = $('配置参数').item.json;
const token = $('获取飞书 Tenant Token').item.json.tenant_access_token;

const platformField = fieldsData.find(f =>
  f.field_name.toUpperCase().includes('SOCIAL MEDIA PLATFORM') ||
  f.field_name.toUpperCase().includes('PLATFORM') ||
  f.field_name.includes('平台')
);

const linkField = fieldsData.find(f =>
  f.field_name.toUpperCase().includes('POSTS LINK') ||
  f.field_name.toUpperCase().includes('LINK') ||
  f.field_name.includes('链接') ||
  f.field_name.includes('URL')
);

const fieldConfig = {
  platformFieldName: platformField?.field_name || 'SOCIAL MEDIA PLATFORM',
  linkFieldName: linkField?.field_name || 'POSTS Link',
  allFields: fieldsData.map(f => ({
    name: f.field_name,
    type: f.type,
    ui_type: f.ui_type,
    field_id: f.field_id,
    property: f.property || null
  }))
};

return {
  json: {
    ...config,
    tenant_access_token: token,
    fieldConfig
  }
};

const tablesData = $json?.data?.items || [];
const config = $('配置参数').item.json;
const token = $('获取飞书 Tenant Token').item.json.tenant_access_token;

const tableNames = tablesData.map(t => t.name);

return {
  json: {
    tableNames,
    year: config.year,
    month: config.month,
    tenant_access_token: token,
    bitableToken: config.bitableToken,
    deepseekApiKey: config.deepseekApiKey
  }
};

const deepseekResp = $json;
const config = $('提取已有表名列表').first().json;
const year = config.year;
const month = config.month;

let tableName;
try {
  const content = deepseekResp?.choices?.[0]?.message?.content || '';
  const parsed = JSON.parse(content);
  tableName = parsed.tableName || parsed.name || parsed.table_name;
  if (!tableName || tableName.length > 100 || /[\/\\?*:\[\]]/.test(tableName)) {
    throw new Error('invalid table name');
  }
} catch (e) {
  tableName = `${year}年${String(parseInt(month))}月`;
}

return {
  json: {
    tableName,
    bitableToken: config.bitableToken,
    tenant_access_token: config.tenant_access_token,
    year,
    month
  }
};

const items = $input.all();
let tableNameData = null;
let fieldConfigData = null;

for (const item of items) {
  if (item.json.tableName) tableNameData = item.json;
  if (item.json.fieldConfig) fieldConfigData = item.json;
}

if (!tableNameData) tableNameData = items[0].json;
if (!fieldConfigData) fieldConfigData = items[items.length - 1].json;

const allFields = fieldConfigData.fieldConfig?.allFields || [];
const skipTypes = [20, 22, 23, 24];

function cleanProperty(prop, fieldType) {
  if (!prop) return undefined;
  const cleaned = JSON.parse(JSON.stringify(prop));
  delete cleaned.table_id;
  delete cleaned.field_id;
  delete cleaned.back_field_id;
  delete cleaned.multiple;
  if (fieldType === 3 || fieldType === 4) {
    if (cleaned.options) {
      cleaned.options = cleaned.options.map(opt => {
        const o = { name: opt.name };
        if (opt.color !== undefined) o.color = opt.color;
        return o;
      });
    }
    return cleaned;
  }
  if (fieldType === 2 || fieldType === 5) return cleaned;
  if (Object.keys(cleaned).length === 0) return undefined;
  return cleaned;
}

const fields = allFields
  .filter(f => !skipTypes.includes(f.type))
  .map(f => {
    const def = { field_name: f.name, type: f.type };
    const prop = cleanProperty(f.property, f.type);
    if (prop) def.property = prop;
    return def;
  });

return {
  json: {
    tableName: tableNameData.tableName,
    bitableToken: tableNameData.bitableToken,
    tenant_access_token: tableNameData.tenant_access_token,
    year: tableNameData.year,
    month: tableNameData.month,
    fieldConfig: fieldConfigData.fieldConfig,
    fields
  }
};

const createResp = $json;
const newTableId = createResp?.data?.table_id;
const config = $('配置参数').item.json;
const fieldConfigNode = $('合并表名与字段配置').first().json;
const token = fieldConfigNode.tenant_access_token;
const year = config.year;
const month = config.month;
const profileUrlsStr = config.profileUrls;
const urls = profileUrlsStr.split(',').map(u => u.trim()).filter(u => u);

const monthInt = parseInt(month);
const yearInt = parseInt(year);
const startDate = `${year}-${month.padStart(2, '0')}-01`;
const nextMonth = monthInt === 12 ? 1 : monthInt + 1;
const nextYear = monthInt === 12 ? yearInt + 1 : yearInt;
const endDate = `${nextYear}-${String(nextMonth).padStart(2, '0')}-01`;
const lastDay = new Date(yearInt, monthInt, 0).getDate();
const endDateInclusive = `${year}-${month.padStart(2, '0')}-${lastDay}`;

const platformGroups = {
  INSTAGRAM: [],
  X: [],
  YOUTUBE: [],
  FACEBOOK: []
};

for (const url of urls) {
  const lower = url.toLowerCase();
  if (lower.includes('instagram.com')) {
    platformGroups.INSTAGRAM.push(url);
  } else if (lower.includes('x.com') || lower.includes('twitter.com')) {
    platformGroups.X.push(url);
  } else if (lower.includes('youtube.com')) {
    platformGroups.YOUTUBE.push(url);
  } else if (lower.includes('facebook.com')) {
    platformGroups.FACEBOOK.push(url);
  }
}

const xUsernames = platformGroups.X.map(url => {
  const match = url.match(/(?:x\.com|twitter\.com)\/([^/?#]+)/);
  return match ? match[1] : null;
}).filter(Boolean);

const xSearchTerms = xUsernames.map(u => `from:${u} since:${startDate} until:${endDate}`);

return {
  json: {
    platformGroups,
    xSearchTerms,
    startDate,
    endDate,
    endDateInclusive,
    year,
    month,
    newTableId,
    bitableToken: config.bitableToken,
    tenant_access_token: token,
    fieldConfig: fieldConfigNode.fieldConfig
  }
};

const data = $json;
const pg = data.platformGroups;
const results = [];

const base = {
  startDate: data.startDate,
  endDate: data.endDate,
  endDateInclusive: data.endDateInclusive,
  year: data.year,
  month: data.month,
  newTableId: data.newTableId,
  bitableToken: data.bitableToken,
  tenant_access_token: data.tenant_access_token,
  fieldConfig: data.fieldConfig
};

if (pg.INSTAGRAM.length > 0) {
  results.push({ json: { ...base, platform: 'INSTAGRAM', urls: pg.INSTAGRAM } });
}
if (pg.X.length > 0) {
  results.push({ json: { ...base, platform: 'X', urls: pg.X, xSearchTerms: data.xSearchTerms } });
}
if (pg.YOUTUBE.length > 0) {
  results.push({ json: { ...base, platform: 'YOUTUBE', urls: pg.YOUTUBE } });
}
if (pg.FACEBOOK.length > 0) {
  results.push({ json: { ...base, platform: 'FACEBOOK', urls: pg.FACEBOOK } });
}

return results;

const scraperData = $('Instagram Scraper').all().map(i => i.json);
const upstreamData = $('If Instagram').first().json;
const allFields = upstreamData.fieldConfig?.allFields || [];
const endDateInclusive = upstreamData.endDateInclusive;

function findFieldConfig(targetName, fields) {
  const t = targetName.toUpperCase();
  return fields.find(f => f.name.toUpperCase().includes(t)) || null;
}

function formatDateField(dateStr, fc) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  const yyyy = String(d.getFullYear());
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const formatted = `${yyyy}/${mm}/${dd}`;
  if (!fc) return formatted;
  if (fc.type === 5) return d.getTime();
  return formatted;
}

function matchOption(value, fc) {
  if (!fc || !value) return null;
  if (fc.type !== 3 && fc.type !== 4) return value;
  const opts = fc.property?.options || [];
  const vUp = value.toUpperCase();
  const match = opts.find(o => o.name.toUpperCase() === vUp);
  if (match) return match.name;
  const partial = opts.find(o => o.name.toUpperCase().includes(vUp) || vUp.includes(o.name.toUpperCase()));
  return partial ? partial.name : null;
}

function matchMultiOptions(values, fc) {
  if (!fc || !values || values.length === 0) return null;
  if (fc.type !== 4) {
    const first = values.find(v => matchOption(v, fc));
    return first ? matchOption(first, fc) : null;
  }
  const opts = fc.property?.options || [];
  const matched = values.map(v => {
    const vUp = v.toUpperCase();
    return opts.find(o => o.name.toUpperCase() === vUp || o.name.toUpperCase().includes(vUp) || vUp.includes(o.name.toUpperCase()));
  }).filter(Boolean).map(o => o.name);
  return matched.length > 0 ? matched : null;
}

const ctaPatterns = [
  { pattern: /link\s*in\s*bio/i, label: 'Link in Bio' },
  { pattern: /shop\s*now/i, label: 'Shop Now' },
  { pattern: /swipe/i, label: 'Swipe' },
  { pattern: /tap\s*(the\s*)?link/i, label: 'Tap Link' },
  { pattern: /check\s*(it\s*)?out/i, label: 'Check Out' },
  { pattern: /subscribe/i, label: 'Subscribe' },
  { pattern: /follow/i, label: 'Follow' },
  { pattern: /sign\s*up/i, label: 'Sign Up' },
  { pattern: /learn\s*more/i, label: 'Learn More' },
  { pattern: /buy\s*now/i, label: 'Buy Now' },
  { pattern: /order\s*now/i, label: 'Order Now' },
  { pattern: /dm\s*(us|me|for)/i, label: 'DM' },
  { pattern: /comment\s*(below|your)/i, label: 'Comment' },
  { pattern: /save\s*this/i, label: 'Save' },
  { pattern: /share\s*(this|with)/i, label: 'Share' },
  { pattern: /click/i, label: 'Click' },
  { pattern: /download/i, label: 'Download' },
  { pattern: /pre-?order/i, label: 'Pre-order' },
  { pattern: /use\s*code/i, label: 'Use Code' },
  { pattern: /grab\s*(yours|it)/i, label: 'Grab Yours' }
];

function extractCTAs(text) {
  if (!text) return [];
  return ctaPatterns.filter(p => p.pattern.test(text)).map(p => p.label);
}

function inferCategory(scraped) {
  const t = (scraped.type || '').toLowerCase();
  if (t === 'video' || t === 'reel' || scraped.videoViewCount || scraped.videoPlayCount) return 'Video';
  if (t === 'sidecar' || t === 'carousel') return 'Carousel';
  if (t === 'image') return 'Image';
  return scraped.caption ? 'Post' : null;
}

function inferSubcategories(scraped) {
  const tags = (scraped.hashtags || []).map(h => h.toLowerCase());
  const caption = (scraped.caption || '').toLowerCase();
  const cats = [];
  if (tags.some(t => ['product', 'newproduct', 'launch', 'shop', 'collection'].includes(t)) || /new\s*(product|launch|collection|arrival)/i.test(caption)) cats.push('Product');
  if (tags.some(t => ['giveaway', 'contest', 'win'].includes(t)) || /giveaway|contest|win\s/i.test(caption)) cats.push('Giveaway');
  if (tags.some(t => ['tutorial', 'howto', 'tips', 'guide', 'diy'].includes(t)) || /how\s*to|tutorial|step\s*by\s*step/i.test(caption)) cats.push('Tutorial');
  if (tags.some(t => ['review', 'unboxing', 'comparison'].includes(t)) || /review|unbox/i.test(caption)) cats.push('Review');
  if (tags.some(t => ['behindthescenes', 'bts', 'makingof'].includes(t)) || /behind\s*the\s*scenes|bts/i.test(caption)) cats.push('Behind The Scenes');
  if (tags.some(t => ['collab', 'collaboration', 'partner', 'sponsored'].includes(t)) || /collab|partner|sponsored/i.test(caption)) cats.push('Collaboration');
  if (tags.some(t => ['announcement', 'news', 'update'].includes(t)) || /announc|breaking/i.test(caption)) cats.push('Announcement');
  if (tags.some(t => ['ugc', 'repost', 'community', 'fanart'].includes(t)) || /repost|community|fan/i.test(caption)) cats.push('UGC');
  if (tags.some(t => ['meme', 'funny', 'humor'].includes(t)) || /meme|funny/i.test(caption)) cats.push('Entertainment');
  return cats;
}

const platformFieldConfig = findFieldConfig('PLATFORM', allFields);
const platformField = platformFieldConfig ? platformFieldConfig.name : null;
const linkFieldConfig = findFieldConfig('LINK', allFields);
const linkField = linkFieldConfig ? linkFieldConfig.name : null;
const likesFieldConfig = findFieldConfig('LIKES', allFields);
const likesField = likesFieldConfig ? likesFieldConfig.name : null;
const commentsFieldConfig = findFieldConfig('COMMENTS', allFields);
const commentsField = commentsFieldConfig ? commentsFieldConfig.name : null;
const impressionsFieldConfig = findFieldConfig('IMPRESSIONS', allFields);
const impressionsField = impressionsFieldConfig ? impressionsFieldConfig.name : null;
const sharesFieldConfig = findFieldConfig('SHARES', allFields);
const sharesField = sharesFieldConfig ? sharesFieldConfig.name : null;
const tagsFieldConfig = findFieldConfig('TAGS', allFields);
const tagsField = tagsFieldConfig ? tagsFieldConfig.name : null;
const dateFieldConfig = findFieldConfig('DATE OF POST', allFields);
const dateField = dateFieldConfig ? dateFieldConfig.name : null;
const catFieldConfig = findFieldConfig('CATEGORIES', allFields);
const catField = catFieldConfig ? catFieldConfig.name : null;
const subCatFieldConfig = findFieldConfig('SUBCATEGORIES', allFields);
const subCatField = subCatFieldConfig ? subCatFieldConfig.name : null;
const audienceFieldConfig = findFieldConfig('TARGET AUDIENCE', allFields);
const audienceField = audienceFieldConfig ? audienceFieldConfig.name : null;
const ctaFieldConfig = findFieldConfig('CALLS TO ACTION', allFields);
const ctaField = ctaFieldConfig ? ctaFieldConfig.name : null;

const endTs = new Date(endDateInclusive + 'T23:59:59.999Z').getTime();

const results = [];
for (const scraped of scraperData) {
  if (scraped.timestamp) {
    const postTs = new Date(scraped.timestamp).getTime();
    if (postTs > endTs) continue;
  }

  const fields = {};
  if (platformField) fields[platformField] = 'Instagram';
  if (linkField && scraped.url) fields[linkField] = { link: scraped.url, text: scraped.url };
  if (likesField && scraped.likesCount !== undefined) {
    const isNum = likesFieldConfig.ui_type === 'Number';
    fields[likesField] = isNum ? scraped.likesCount : scraped.likesCount.toString();
  }
  if (commentsField && scraped.commentsCount !== undefined) {
    const isNum = commentsFieldConfig.ui_type === 'Number';
    fields[commentsField] = isNum ? scraped.commentsCount : scraped.commentsCount.toString();
  }
  if (impressionsField && (scraped.videoViewCount !== undefined || scraped.videoPlayCount !== undefined)) {
    const isNum = impressionsFieldConfig.ui_type === 'Number';
    const val = scraped.videoViewCount !== undefined ? scraped.videoViewCount : scraped.videoPlayCount;
    fields[impressionsField] = isNum ? val : val.toString();
  }
  if (sharesField && scraped.sharesCount !== undefined) {
    const isNum = sharesFieldConfig.ui_type === 'Number';
    fields[sharesField] = isNum ? scraped.sharesCount : scraped.sharesCount.toString();
  }
  if (tagsField && scraped.hashtags && scraped.hashtags.length > 0) {
    const tagsText = scraped.hashtags.map(h => `#${h}`).join(' ');
    const isLink = tagsFieldConfig.ui_type === 'Url';
    fields[tagsField] = isLink ? { link: scraped.url || '', text: tagsText } : tagsText;
  }

  if (dateField) {
    const dv = formatDateField(scraped.timestamp, dateFieldConfig);
    if (dv !== null) fields[dateField] = dv;
  }
  if (catField) {
    const cat = inferCategory(scraped);
    if (cat) {
      const mv = matchOption(cat, catFieldConfig);
      if (mv) fields[catField] = mv;
    }
  }
  if (subCatField) {
    const subs = inferSubcategories(scraped);
    if (subs.length > 0) {
      const mv = matchMultiOptions(subs, subCatFieldConfig);
      if (mv) fields[subCatField] = mv;
    }
  }
  if (ctaField) {
    const ctas = extractCTAs(scraped.caption);
    if (ctas.length > 0) {
      const mv = matchMultiOptions(ctas, ctaFieldConfig);
      if (mv) fields[ctaField] = mv;
    }
  }

  results.push({ json: { fields } });
}

if (results.length === 0) {
  return [{ json: { _empty: true, platform: 'Instagram' } }];
}
return results;

const scraperData = $('X / Twitter Scraper').all().map(i => i.json);
const upstreamData = $('If X/Twitter').first().json;
const allFields = upstreamData.fieldConfig?.allFields || [];

function findFieldConfig(targetName, fields) {
  const t = targetName.toUpperCase();
  return fields.find(f => f.name.toUpperCase().includes(t)) || null;
}

function formatDateField(dateStr, fc) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  const yyyy = String(d.getFullYear());
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const formatted = `${yyyy}/${mm}/${dd}`;
  if (!fc) return formatted;
  if (fc.type === 5) return d.getTime();
  return formatted;
}

function matchOption(value, fc) {
  if (!fc || !value) return null;
  if (fc.type !== 3 && fc.type !== 4) return value;
  const opts = fc.property?.options || [];
  const vUp = value.toUpperCase();
  const match = opts.find(o => o.name.toUpperCase() === vUp);
  if (match) return match.name;
  const partial = opts.find(o => o.name.toUpperCase().includes(vUp) || vUp.includes(o.name.toUpperCase()));
  return partial ? partial.name : null;
}

function matchMultiOptions(values, fc) {
  if (!fc || !values || values.length === 0) return null;
  if (fc.type !== 4) {
    const first = values.find(v => matchOption(v, fc));
    return first ? matchOption(first, fc) : null;
  }
  const opts = fc.property?.options || [];
  const matched = values.map(v => {
    const vUp = v.toUpperCase();
    return opts.find(o => o.name.toUpperCase() === vUp || o.name.toUpperCase().includes(vUp) || vUp.includes(o.name.toUpperCase()));
  }).filter(Boolean).map(o => o.name);
  return matched.length > 0 ? matched : null;
}

const ctaPatterns = [
  { pattern: /link\s*in\s*bio/i, label: 'Link in Bio' },
  { pattern: /shop\s*now/i, label: 'Shop Now' },
  { pattern: /swipe/i, label: 'Swipe' },
  { pattern: /tap\s*(the\s*)?link/i, label: 'Tap Link' },
  { pattern: /check\s*(it\s*)?out/i, label: 'Check Out' },
  { pattern: /subscribe/i, label: 'Subscribe' },
  { pattern: /follow/i, label: 'Follow' },
  { pattern: /sign\s*up/i, label: 'Sign Up' },
  { pattern: /learn\s*more/i, label: 'Learn More' },
  { pattern: /buy\s*now/i, label: 'Buy Now' },
  { pattern: /order\s*now/i, label: 'Order Now' },
  { pattern: /dm\s*(us|me|for)/i, label: 'DM' },
  { pattern: /comment\s*(below|your)/i, label: 'Comment' },
  { pattern: /retweet/i, label: 'Retweet' },
  { pattern: /share\s*(this|with)/i, label: 'Share' },
  { pattern: /click/i, label: 'Click' },
  { pattern: /download/i, label: 'Download' },
  { pattern: /pre-?order/i, label: 'Pre-order' },
  { pattern: /use\s*code/i, label: 'Use Code' },
  { pattern: /grab\s*(yours|it)/i, label: 'Grab Yours' }
];

function extractCTAs(text) {
  if (!text) return [];
  return ctaPatterns.filter(p => p.pattern.test(text)).map(p => p.label);
}

function inferCategory(scraped) {
  if (scraped.media?.length > 0) {
    const hasVideo = scraped.media.some(m => m.type === 'video' || m.video_info);
    if (hasVideo) return 'Video';
    if (scraped.media.length > 1) return 'Carousel';
    return 'Image';
  }
  if (scraped.isQuoteStatus || scraped.quotedTweet) return 'Quote';
  if (scraped.isRetweet) return 'Retweet';
  return 'Text';
}

function inferSubcategories(scraped) {
  const tags = (scraped.entities?.hashtags || []).map(h => h.text?.toLowerCase() || h.toLowerCase());
  const text = (scraped.text || scraped.fullText || '').toLowerCase();
  const cats = [];
  if (tags.some(t => ['product', 'newproduct', 'launch', 'shop', 'collection'].includes(t)) || /new\s*(product|launch|collection|arrival)/i.test(text)) cats.push('Product');
  if (tags.some(t => ['giveaway', 'contest', 'win'].includes(t)) || /giveaway|contest|win\s/i.test(text)) cats.push('Giveaway');
  if (tags.some(t => ['tutorial', 'howto', 'tips', 'guide', 'thread'].includes(t)) || /thread|how\s*to|tutorial/i.test(text)) cats.push('Tutorial');
  if (tags.some(t => ['review', 'unboxing', 'comparison'].includes(t)) || /review|unbox/i.test(text)) cats.push('Review');
  if (tags.some(t => ['behindthescenes', 'bts'].includes(t)) || /behind\s*the\s*scenes|bts/i.test(text)) cats.push('Behind The Scenes');
  if (tags.some(t => ['collab', 'collaboration', 'partner', 'sponsored', 'ad'].includes(t)) || /collab|partner|sponsored|#ad\b/i.test(text)) cats.push('Collaboration');
  if (tags.some(t => ['announcement', 'news', 'update', 'breaking'].includes(t)) || /announc|breaking/i.test(text)) cats.push('Announcement');
  if (/poll|vote|which\s*one|what\s*do\s*you/i.test(text)) cats.push('Engagement');
  return cats;
}

const platformFieldConfig = findFieldConfig('PLATFORM', allFields);
const platformField = platformFieldConfig ? platformFieldConfig.name : null;
const linkFieldConfig = findFieldConfig('LINK', allFields);
const linkField = linkFieldConfig ? linkFieldConfig.name : null;
const likesFieldConfig = findFieldConfig('LIKES', allFields);
const likesField = likesFieldConfig ? likesFieldConfig.name : null;
const commentsFieldConfig = findFieldConfig('COMMENTS', allFields);
const commentsField = commentsFieldConfig ? commentsFieldConfig.name : null;
const impressionsFieldConfig = findFieldConfig('IMPRESSIONS', allFields);
const impressionsField = impressionsFieldConfig ? impressionsFieldConfig.name : null;
const sharesFieldConfig = findFieldConfig('SHARES', allFields);
const sharesField = sharesFieldConfig ? sharesFieldConfig.name : null;
const tagsFieldConfig = findFieldConfig('TAGS', allFields);
const tagsField = tagsFieldConfig ? tagsFieldConfig.name : null;
const dateFieldConfig = findFieldConfig('DATE OF POST', allFields);
const dateField = dateFieldConfig ? dateFieldConfig.name : null;
const catFieldConfig = findFieldConfig('CATEGORIES', allFields);
const catField = catFieldConfig ? catFieldConfig.name : null;
const subCatFieldConfig = findFieldConfig('SUBCATEGORIES', allFields);
const subCatField = subCatFieldConfig ? subCatFieldConfig.name : null;
const audienceFieldConfig = findFieldConfig('TARGET AUDIENCE', allFields);
const audienceField = audienceFieldConfig ? audienceFieldConfig.name : null;
const ctaFieldConfig = findFieldConfig('CALLS TO ACTION', allFields);
const ctaField = ctaFieldConfig ? ctaFieldConfig.name : null;

const results = [];
for (const scraped of scraperData) {
  const fields = {};
  if (platformField) fields[platformField] = 'X';
  if (linkField && (scraped.url || scraped.twitterUrl)) {
    const postUrl = scraped.url || scraped.twitterUrl;
    fields[linkField] = { link: postUrl, text: postUrl };
  }
  if (likesField && scraped.likeCount !== undefined) {
    const isNum = likesFieldConfig.ui_type === 'Number';
    fields[likesField] = isNum ? scraped.likeCount : scraped.likeCount.toString();
  }
  if (commentsField && scraped.replyCount !== undefined) {
    const isNum = commentsFieldConfig.ui_type === 'Number';
    fields[commentsField] = isNum ? scraped.replyCount : scraped.replyCount.toString();
  }
